+              << "  --baudrate VALUE                  Set the baudrate (default " << kBaudRate << "bps)\n"
+              << "  --timeout VALUE                   Set the read/write timeout (default " << kTimeout << "ms)\n"
+              << "  --slave-address VALUE             Set the slave address (default " << kSlaveAddress << ")\n"
